using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders; using Norge360.Community.Domain.Entities; namespace Norge360.Community.Infrastructure.Persistence.Configurations; public sealed class CommunityPostReactionConfiguration : IEntityTypeConfiguration<CommunityPostReaction>{ public void Configure(EntityTypeBuilder<CommunityPostReaction> b){ b.ToTable("CommunityPostReactions"); b.HasKey(x=>x.Id); b.Property(x=>x.Emoji).HasMaxLength(32).IsRequired(); b.Property(x=>x.EmojiCode).HasMaxLength(64).IsRequired(); b.HasIndex(x=>new{x.PostId,x.UserId}).IsUnique().HasFilter("\"IsDeleted\" = false"); b.HasQueryFilter(x=>!x.IsDeleted); }}
